def add(a, b):
    return a + b
class Greeter:
    def hello(self, name):
        return f'hello {name}'
def normalize(items):
    total = sum(items)
    if not total:
        return []
    return [item / total for item in items]
def clamp(x, lo, hi):
    if x < lo:
        return lo
    if x > hi:
        return hi
    return x
def render_user(user):
    return {'id': user['id'], 'name': user['name']}
class Counter:
    def __init__(self):
        self.value = 0
    def inc(self):
        self.value += 1
        return self.value
def pairwise_sum(items):
    result = []
    for idx in range(0, len(items), 2):
        result.append(sum(items[idx:idx+2]))
    return result
